import{_ as i,o as n,c as r,ag as t}from"./chunks/framework.DXGyWiRo.js";const l="/images/uebung061.jpg",s="/images/uebung060.jpg",a="/images/uebung059.jpg",b=JSON.parse('{"title":"Übung Lektion 36","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung36.md","filePath":"lektionen/uebung36.md"}'),o={name:"lektionen/uebung36.md"};function p(d,e,u,g,h,m){return n(),r("div",null,[...e[0]||(e[0]=[t('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-36" tabindex="-1">Übung Lektion 36 <a class="header-anchor" href="#ubung-lektion-36" aria-label="Permalink to &quot;Übung Lektion 36&quot;">​</a></h1><p>A) Folgende Wurzeln haben sowohl redupliziertes wie periphrastisches Perfekt. Bilden Sie zu folgenden Formen die entsprechenden periphrastischen und reduplizierten Perfektformen:</p><ol><li>बिभ्रते । बभ्रिरे । बिभरां चक्रिरे । बिभरामासुर् । बुभरां बभूवुर्</li><li>बिभ्यति । बिभ्युर् । बिभयां चक्रुर् । बिभयामासुर् । बिभयां बभूवुर्</li><li>जुहोति । जुहाव । जुहवां चकार । जुहवामास । जुहवां बभूव</li><li>वेत्ति । विवेद । विदां चकार । विदामास । विदां बभूव</li></ol><p>B) Die Wurzel आस् &quot;sitzen&quot; hat periphrastisches Perfekt. Bilden sie dieses zu folgenden Formen:</p><ol><li>आस्ते । आसां चक्रे । आसामास । आसां बभूव</li><li>आसते । आसां चक्रिरे । आसामासुर् । आसां बभूवुर्</li></ol><p>C) Bilden Sie das entsprechende Perfekt zu folgenden Formen:</p><ol><li>जीयते । जिग्ये</li><li>विदन्ति । विदुर् । विविदुर् । विदां चक्रुर् । विदामासुर् । विदां बभूवुर्</li><li>विन्दति । विवेद</li><li>त्याजयिष्यति । त्याजयां चकार । त्याजयामास । त्याजयां बभूव</li><li>ऐक्षन्त । ईक्षां चक्रिरे । ईक्षां बभूवुर् । ईक्षामासुर्</li><li>अगापयत् । गापयां चकार । गापयां बभूव । गापयामास</li><li>अपद्यन्त । पेदिरे</li><li>चिनोति (2 Formen) । चिकाय । चिचाय</li><li>हन्ति । जघान</li><li>प्रभविष्यन्ति । प्रबभूवुर्</li><li>क्रामन्ति । चक्रमुर्</li><li>प्राव्रजन् । प्रवव्रजुर्</li><li>त्यक्ष्यति । तत्याज</li></ol><p>D) Übersetzen Sie:</p><p>पुत्रे जाते सुगतः कुलं धनं च तत्याजागाराच्चानगर्यं प्रवव्राज । बुद्ध्यार्यसत्यानि प्रज्ञाय प्रज्ञया च दुःखान्मुक्तो मोक्तुकामार्यजनान्बोधयामासेति भिक्षव आहुः ॥१॥</p><p>Als ihm ein Sohn geboren war, verließ der Wegvollender Familie und Besitz und ging aus dem Heim in die Heimlosigkeit. Er erkannte mit seinem Verstand die Edlen Wahrheiten, wurde durch die Erkenntnis vom Leiden befreit und brachte die edlen Menschen, die Erlösung wünschten, zur Einsicht. All dies sagen die Mönche.</p><p>ब्राह्मणा महादेवयज्ञायाग्निं चिक्यिरे । ब्राह्मणेष्विन्द्रादिदेवान्स्तुवत्स्वग्निर्यज्ञान्नमाश । एवं यज्ञेन ब्राह्मणा महादेवैरादयां चक्रुस्तांश्च स्तोत्रानि श्रावयां बभूवुः ॥२॥</p><p>Die Brahmanen schichteten für das große Götteropfer ein Feuer auf. Während die Brahmanen Indra und die anderen Götter priesen, verzehrte das Opferfeuer die Speise. So gaben die Brahmanen durch das Opfer den großen Göttern zu Essen und ließen sie Lobeshymnen hören.</p><p>रक्षितधर्मक्षत्रिययोधा महानगरं जेतुकामाञ्छत्रून्विजिग्युर्न तु जघ्नुः ॥३॥</p><p>Die Kṣatriyakrieger, die das Recht hüteten, besiegten die Feinde, die die große Stadt erobern wollten, töteten sie aber nicht.</p><p>अधीतवेदद्विजो द्विजधर्मं वेद ॥४॥</p><p>Ein Zweimalgeborener, der den Veda studiert hat, kennt Recht und Sitte der Zweimalgeborenen.</p><p>विद्ययैव जीवितुं न शक्यते । य एवं विदुर्नाधीयीरन् ॥५॥</p><p>Von Wissenschaft kann man nicht leben. Wer das weiß, sollte nicht studieren.</p><p>स साधुर्दुर्जनपापलोभमतिमीक्षां चक्रे ॥६॥</p><p>Dieser Heilige sah das böse, gierige Herz der bösen Leute.</p><p>ब्राह्मणीभिः स्वान्नानि पेचिरे ॥७॥</p><p>Die Brahmaninnen haben feine Speisen gekocht.</p><p><img src="'+l+'" alt=""><br> Abb.: विद्ययैव जीवितुं न शक्यते<br> Banaras Hindu University (BHU) = काशी हिन्दू विश्वविद्यालय<br> [Bildquelle: onbangladesh. -- <a href="http://www.flickr.com/photos/onbangladesh/2900792661/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/onbangladesh/2900792661/</a>. -- Zugriff am 2009-01-20. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung,  krinr kommerzielle Nutzung)]</p><p>Übersetzen Sie:</p><p>1. महाभारत १३.७.२५-२६</p><blockquote><p>येन प्रीणति पितरं<br> तेन प्रीतः प्रजापतिः ।<br> प्रीणति मातरं येन<br> पृथिवी तेन पूजिता ।<br> येन प्रीणात्युपाध्यायं<br> तेन स्याद्ब्रह्म पूजितम् ।<br> सर्वे तस्यादृता धर्मा<br> यस्यैते त्रय आदृताः ।<br> अनादृतास्तु यस्यैते<br> सर्वास्तस्याफलाः क्रियाः ॥</p><p>Womit man seinen Vater erfreut, damit wird der Schöpfer erfreut;<br> Womit man seine Mutter erfreut, damit wird die Erde verehrt;<br> Womit man den Lehrer erfreut, damit wird der Veda verehrt.<br> Wer diese drei achtet, der achtet alle Vorschriften,<br> Wer diese nicht achtet, von dem fruchten alle Rituale nichts.</p></blockquote><p>2. मनुस्मृति ४.१५४ über der rechte Verhalten gegenüber Alten:</p><blockquote><p>अभिवादयेद्वृद्धांश्च दद्याच्चैवासनं स्वकम् ।<br> कृताञ्जलिरुपासीत गच्छतः पृष्ठतो ऽन्वियात् ॥</p><p>Man begrüße Alte formgerecht, überlasse ihnen seinen Sitz und stehe bei ihnen mit gefalteten Händen. wenn ein Alter geht, gehe man hinter ihm.</p></blockquote><p>3. मनुस्मृति २.९८: Wer ein जितेन्द्रिय ist:</p><blockquote><p>श्रुत्वा स्पृष्ट्वा च दृष्ट्वा च भुक्त्वा घ्रात्वा च यो नरः ।<br> न हृष्यति ग्लायति वा स विज्ञेयो जितेन्द्रियः ॥</p><p>Wenn ein Mann sich nicht freut oder verdrießt, wenn er hört, berührt, sieht, schmeckt oder richt, dann kann man wissen, dass er seine Sinne besiegt hat.</p></blockquote><p>4. मनुस्मृति २.११० über rechte Verhalten eines Brahmanen:</p><blockquote><p>नापृष्टः कस्यचिद्ब्रूयान्न चान्यायेन पृच्छतः ।<br> जानन्नपि हि मेधावी जडवल्लोक आचरेत् ॥</p><p>Nicht soll er etwas sagen, wenn er nicht gefragt wird, auch nicht, wenn er in ungehöriger Weise gefragt wird.<br> Auch ein wissender Weiser soll sich in der Welt wie ein Dummkopf geben.</p></blockquote><p><img src="'+s+'" alt=""><br> Abb.: भुक्त्वा घ्रात्वा च न हृष्यति ग्लायति वा<br> Sikkim = सिक्किम<br> [Bildquelle: juicyrai. -- <a href="http://www.flickr.com/photos/wink/234707341/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/wink/234707341/</a>. -- Zugriff am 2009-01-20. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><p>Bestimmen und übersetzen Sie folgende Wortformen auf alle möglichen Weisen:</p><p>(Auflösung ohne Anspruch auf Vollständigkeit!)</p><ol><li>नयति । नी  3.sg.P ; Part.Präs.Lok.sg.m.n.</li><li>समस्कुर्वन् । सम्-कृ Imperf.3.pl.P</li><li>स्यात् । अस् 2P Opt.3.sg.P</li><li>यस्याम् । यद् Lok.sg.f.</li><li>अधीयते । अधि-इ 2Ā 3.pl.Ā ; Pass.3.sg.</li><li>प्रोचुः । प्र-वच् 2P Perf.3.pl.P</li><li>समादधाति । सम्-आ-धा 3.pl.P ; Part.Präs.P.Nom.Akk.pl.n. ; Part.Präs.P.Lok.sg.m.n.</li><li>हरेः । हरि &quot;gelb&quot; Abl.Gen.sg.m.</li><li>हरे । हर Lok.sg.m.</li><li>हरेत् । हृ 1U Opt.3.sg.P</li><li>जह्रे । हृ 1U Perf.3.sg.Ā</li><li>आक्रीणीत । आ-क्री 9U Impf.3.sg.Ā ; Opt.3.sg.Ā</li><li>व्यक्रियत । वि-कृ 8U &quot;verändern, schaffen ; durcheinander bringen&quot; Impf.3.sg.Pass</li><li>प्राजहुः । प्र-हा 3P Impf.3.pl.P</li><li>प्रजहुः । प्र-हा 3P Perf.3.pl.P</li><li>ददे । दा 3U Perf.3.sg.Ā</li><li>दत्ते । दा 3U 3.sg.Ā ; PPP.Lok.sg.m.n.</li><li>हिते । धा 3U PPP.Lok.sg.m.n. ; हित n. &quot;Wohlergehen&quot; Lok.sg.n.</li><li>हीयते । हा 3P Pass.3.sg.</li><li>जज्ञे । ज्ञा 9U und जन् 4Ā Perf.3.sg.Ā</li><li>यज्ञे । यज्ञ m. Lok.sg.m.</li><li>तेन । तद् Instr.sg.m.n.</li><li>तेने । तन् 8U Perf.3.sg.Ā</li><li>ततः । &quot;darauf&quot; ; तन् 8U PPP.Nom.sg.m.</li><li>सतः । अस् 2P Part.Präs.P.Gen.Abl.sg.m.n. ; Part.Präs.P.Akk.pl.m.</li><li>जगौ । गै 1P Perf.3.sg.P</li><li>पशौ । पशु m. Lok.sg.m.</li><li>मेने । मन् 4Ā Perf.3.sg.Ā</li><li>माने । मान n. &quot;das Messen&quot;, &quot;der Stolz ...&quot; Lok.sg.n.</li><li>एतस्मात् । एतद् Abl.sg.m.n.</li><li>तायेत । तन् 8U Pass.Opt.3.sg. (neben तन्येत)</li><li>तया । तद् Instr.sg.f.</li><li>लेभिरे । लभ् 1Ā Perf.3.pl.Ā</li><li>ओषुः । आ-वस् 1P &quot;beiwohnen = beischlafen&quot; Perf.3.pl.P</li><li>व्यानक् । वि-अञ्ज् 7P &quot;offenbaren&quot; Impf.3.sg.P</li><li>युङ्क्ते । युज् 7U 3.sg.Ā</li><li>r&quot; Lok.sg.n.</li><li>अपिपः । पॄ 3P Impf.3.</li><li>युक्ते । युज् 7U PPP.Lok.sg.m.n.</li><li>युगे । युग n. &quot;Joch, Paasg.P</li><li>अपिबत् । पा 1P &quot;trinken&quot; Impf.3.sg.P</li></ol><p><img src="'+a+'" alt=""><br> Abb.: जगौ<br> Baul = বাউল mit Dotara = দোতারা, Shantikniketan = শান্তিনিকেতন<br> [Bildquelle: paulancheta. -- <a href="http://www.flickr.com/photos/paulancheta/3164774529/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/paulancheta/3164774529/</a>. -- Zugriff am 2009-01-20. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielel Nutzung, keine Bearbeitung)]</p>',38)])])}const f=i(o,[["render",p]]);export{b as __pageData,f as default};
